a:link {
  color: blue;
  text-decoration: underline;
}

a:visited {
  color: purple;
}

a:link {
  color: blue;
  text-decoration: none;
  border-bottom: 1px solid blue;
}

a:visited {
  color: purple;
  border-bottom: 1px solid purple;
}

a:hover {
  color: red;
}

a:active {
  color: darkorange;
}
